-- SynDrasi Migration 034 - complete non-municipality mission playbooks
-- Adds playbooks for every Fire Service, Civil Protection and Coast Guard category.

CREATE TEMPORARY TABLE tmp_event_playbooks_complete (
  authority_type ENUM('municipality','civil_protection','fire_service','coast_guard') NOT NULL,
  category_name VARCHAR(150) NOT NULL,
  title VARCHAR(180) NOT NULL,
  default_people INT NOT NULL DEFAULT 0,
  require_vehicle TINYINT(1) NOT NULL DEFAULT 0,
  require_medical TINYINT(1) NOT NULL DEFAULT 0,
  instructions TEXT NULL,
  capabilities_json TEXT NULL,
  checklist_json TEXT NULL,
  messages_json TEXT NULL,
  debrief_questions_json TEXT NULL
) ENGINE=InnoDB;

INSERT INTO tmp_event_playbooks_complete
(authority_type, category_name, title, default_people, require_vehicle, require_medical, instructions, capabilities_json, checklist_json, messages_json, debrief_questions_json)
VALUES
('fire_service', 'Παροχή βοήθειας', 'Πρωτόκολλο παροχής βοήθειας', 4, 1, 1,
'Προσέλευση με βασικό εξοπλισμό υποστήριξης, όχημα όπου υπάρχει και δυνατότητα πρώτων βοηθειών. Αναφέρετε άμεσα το είδος βοήθειας που μπορείτε να προσφέρετε.',
'["Όχημα","Πρώτες βοήθειες","Φακοί","Ασύρματοι","Βασικά εργαλεία"]',
'["Επιβεβαίωση ακριβούς ανάγκης και τοποθεσίας","Καταγραφή διαθέσιμων ομάδων και εξοπλισμού","Ορισμός ασφαλούς σημείου συνάντησης","Αίτημα κατάστασης από την πρώτη ομάδα που φτάνει","Ενημέρωση αν απαιτείται επιπλέον υπηρεσία"]',
'["Αναφέρετε διαθέσιμο προσωπικό, όχημα και ETA.","Στείλτε στίγμα όταν φτάσετε στο σημείο.","Μην επιχειρείτε χωρίς ασφαλή πρόσβαση."]',
'["Ήταν σαφής η ανάγκη βοήθειας?","Υπήρχε επαρκής εξοπλισμός?","Τι θα επιτάχυνε την ανταπόκριση?"]'),
('fire_service', 'Έρευνα αγνοουμένου', 'Πρωτόκολλο έρευνας αγνοουμένου', 10, 1, 1,
'Προσέλευση στο σημείο συντονισμού. Δηλώστε διαθέσιμα άτομα, οχήματα, φωτισμό, drone ή γνώση περιοχής. Καμία ομάδα δεν κινείται μόνη χωρίς ανάθεση τομέα.',
'["Ομάδες πεζής έρευνας","4x4","Drone","Φακοί","Ασύρματοι","Πρώτες βοήθειες","Χάρτες/τοπική γνώση"]',
'["Συλλογή τελευταίου γνωστού σημείου και περιγραφής","Ορισμός τομέων έρευνας και υπευθύνων","Καταγραφή ομάδων εισόδου/εξόδου ανά τομέα","Αίτημα περιοδικού GPS από κάθε ομάδα","Σημείο πρώτων βοηθειών και παραλαβής ευρήματος","Συντονισμός με ΕΛΑΣ/Πυροσβεστική όπου απαιτείται"]',
'["Μην ξεκινήσετε έρευνα χωρίς ανάθεση τομέα.","Στείλτε GPS ανά 15 λεπτά και αναφέρετε κάθε εύρημα.","Κρατήστε ζεύγη ή μικρές ομάδες για λόγους ασφάλειας."]',
'["Ήταν σωστός ο χωρισμός τομέων?","Πόσο καλά λειτούργησε η αναφορά GPS?","Υπήρξαν κενά σε εξοπλισμό ή επικοινωνίες?"]'),
('fire_service', 'Πλημμυρικό συμβάν', 'Πρωτόκολλο πλημμυρικού συμβάντος', 8, 1, 1,
'Προσέλευση με προτεραιότητα στην ασφάλεια ομάδων, σήμανση, υποστήριξη εγκλωβισμένων και ενημέρωση για στάθμη υδάτων.',
'["4x4","Αντλίες","Γαλότσες/αδιάβροχα","Σήμανση","Πρώτες βοήθειες","Φακοί"]',
'["Χαρτογράφηση πλημμυρισμένων σημείων","Αποκλεισμός επικίνδυνων διελεύσεων","Καταγραφή εγκλωβισμένων ή ευάλωτων πολιτών","Συντονισμός αντλήσεων/μεταφορών","Αίτημα φωτογραφιών από κρίσιμα σημεία","Συνεχής ενημέρωση στάθμης νερού"]',
'["Μην επιχειρείτε διέλευση από νερά με ρεύμα.","Στείλτε φωτογραφία και στίγμα επικίνδυνου σημείου.","Αναφέρετε άμεσα εγκλωβισμένους ή ανάγκη μεταφοράς."]',
'["Ποια σημεία ήταν πιο επικίνδυνα?","Υπήρχαν αρκετές αντλίες/οχήματα?","Πώς λειτούργησε η ενημέρωση ομάδων?"]'),
('fire_service', 'Επιφυλακή / κάλυψη περιοχής', 'Πρωτόκολλο επιφυλακής περιοχής', 4, 1, 0,
'Οι ομάδες καλύπτουν προκαθορισμένους τομείς, παραμένουν σε ετοιμότητα και στέλνουν περιοδική ενημέρωση κατάστασης.',
'["Όχημα περιπολίας","Ασύρματοι","Φακοί","Χάρτης περιοχής","Βασικό φαρμακείο"]',
'["Ορισμός τομέων κάλυψης","Καταγραφή διαθέσιμων ομάδων και ωραρίων","Πρώτη αναφορά κατάστασης ανά τομέα","Περιοδικό check-in ανά 30 λεπτά","Καταγραφή συμβάντων ή ύποπτων σημείων","Ετοιμότητα για ανακατεύθυνση ομάδας"]',
'["Αναλάβετε τομέα και στείλτε πρώτη κατάσταση.","Στείλτε check-in ανά 30 λεπτά ή άμεσα αν υπάρξει συμβάν.","Παραμείνετε διαθέσιμοι για ανακατεύθυνση."]',
'["Ήταν σωστή η κάλυψη τομέων?","Υπήρξαν κενά χρόνου ή περιοχής?","Πόσο χρήσιμα ήταν τα περιοδικά check-ins?"]'),
('civil_protection', 'Εκκένωση', 'Πρωτόκολλο εκκένωσης', 12, 1, 1,
'Προτεραιότητα στην ασφαλή καθοδήγηση πολιτών, ευάλωτων ομάδων και οχημάτων προς τα σημεία συγκέντρωσης.',
'["Οχήματα μεταφοράς","Πρώτες βοήθειες","Σήμανση","Ασύρματοι","Λίστες ευάλωτων πολιτών","Φακοί"]',
'["Επιβεβαίωση περιοχής εκκένωσης και διαδρομών","Ορισμός σημείων συγκέντρωσης","Ανάθεση ομάδων σε πόρτα-πόρτα ή κυκλοφορία","Καταγραφή ευάλωτων πολιτών και μεταφορών","Συντονισμός με ΕΛΑΣ/Δήμο/ΕΚΑΒ","Ενημέρωση ολοκλήρωσης ανά τομέα"]',
'["Μεταβείτε στον τομέα σας και αναφέρετε έναρξη εκκένωσης.","Προτεραιότητα σε ηλικιωμένους, ΑμεΑ και παιδιά.","Αναφέρετε μπλοκαρισμένες διαδρομές ή άρνηση αποχώρησης."]',
'["Ήταν σαφείς οι διαδρομές εκκένωσης?","Ποια ευάλωτη ομάδα χρειάστηκε περισσότερη υποστήριξη?","Τι πρέπει να αλλάξει στο σχέδιο εκκένωσης?"]'),
('civil_protection', 'Διανομή ειδών ανάγκης', 'Πρωτόκολλο διανομής ειδών ανάγκης', 6, 1, 0,
'Οργανωμένη παραλαβή, καταγραφή, φόρτωση και διανομή ειδών ανάγκης με προτεραιότητα σε ευάλωτους πολίτες και απομονωμένες περιοχές.',
'["Όχημα μεταφοράς","Αποθήκη/σημείο διανομής","Λίστες παραληπτών","Κούτες/παλέτες","Εθελοντές καταγραφής"]',
'["Καταγραφή διαθέσιμων ειδών και ποσοτήτων","Ορισμός σημείου παραλαβής/διανομής","Προτεραιοποίηση περιοχών και ευάλωτων πολιτών","Ανάθεση οχημάτων και δρομολογίων","Επιβεβαίωση παραδόσεων","Αναφορά ελλείψεων αποθέματος"]',
'["Αναφέρετε όχημα, χωρητικότητα και διαθέσιμα άτομα.","Παραλάβετε μόνο με καταγραφή ποσοτήτων.","Επιβεβαιώστε κάθε παράδοση με σύντομη αναφορά."]',
'["Ήταν σωστή η προτεραιοποίηση περιοχών?","Υπήρχαν ελλείψεις ειδών?","Πώς λειτούργησε η καταγραφή παραδόσεων?"]'),
('civil_protection', 'Υποστήριξη καταυλισμού', 'Πρωτόκολλο υποστήριξης καταυλισμού', 8, 1, 1,
'Υποστήριξη προσωρινού χώρου φιλοξενίας με καταγραφή αναγκών, ροές πολιτών, πρώτες βοήθειες και διανομή ειδών.',
'["Πρώτες βοήθειες","Σκηνές/κουβέρτες","Νερό/τρόφιμα","Καταγραφή πολιτών","Φωτισμός","Όχημα"]',
'["Έλεγχος χωρητικότητας και βασικών υποδομών","Ορισμός σημείων εισόδου/καταγραφής","Διαχωρισμός ευάλωτων πολιτών","Οργάνωση διανομής ειδών","Σημείο πρώτων βοηθειών","Περιοδική αναφορά αναγκών"]',
'["Μεταβείτε στο σημείο φιλοξενίας και αναφέρετε ανάγκες.","Καταγράψτε ευάλωτους πολίτες και άμεσες ελλείψεις.","Κρατήστε καθαρές ροές εισόδου και διανομής."]',
'["Ήταν επαρκείς οι υποδομές καταυλισμού?","Ποιες ανάγκες εμφανίστηκαν πρώτες?","Τι βελτιώνει την καταγραφή πολιτών?"]'),
('civil_protection', 'Έλεγχος υποδομών', 'Πρωτόκολλο ελέγχου υποδομών', 5, 1, 0,
'Έλεγχος κρίσιμων υποδομών με φωτογραφική τεκμηρίωση, στίγμα και ταξινόμηση κινδύνου. Δεν γίνεται επέμβαση χωρίς αρμόδιο τεχνικό όπου απαιτείται.',
'["Όχημα","Φωτογραφική τεκμηρίωση","Φακοί","Ασύρματοι","Μηχανικός/τεχνικός","Σήμανση"]',
'["Λίστα κρίσιμων υποδομών προς έλεγχο","Ανάθεση σημείων σε ομάδες","Φωτογραφία και στίγμα ανά σημείο","Ταξινόμηση κινδύνου χαμηλό/μέσο/υψηλό","Σήμανση επικίνδυνων περιοχών","Συγκεντρωτική αναφορά ευρημάτων"]',
'["Ελέγξτε μόνο το σημείο που σας ανατέθηκε και στείλτε φωτογραφία/στίγμα.","Μην εισέρχεστε σε ασταθή υποδομή.","Αναφέρετε άμεσα υψηλό κίνδυνο ή ανάγκη αποκλεισμού."]',
'["Ήταν πλήρης η λίστα υποδομών?","Πόσο χρήσιμη ήταν η φωτογραφική τεκμηρίωση?","Ποια σημεία χρειάζονται επανέλεγχο?"]'),
('civil_protection', 'Συντονισμός εθελοντών', 'Πρωτόκολλο συντονισμού εθελοντών', 4, 0, 0,
'Στήσιμο κέντρου συντονισμού εθελοντών με καταγραφή παρουσιών, δεξιοτήτων, αναθέσεων και αλλαγών βάρδιας.',
'["Καταγραφή εθελοντών","Ασύρματοι/τηλέφωνα","Λίστες βαρδιών","Σημείο ενημέρωσης","Υπεύθυνος τομέων"]',
'["Άνοιγμα σημείου καταγραφής εθελοντών","Καταγραφή δεξιοτήτων και διαθεσιμότητας","Ανάθεση ρόλων και τομέων","Ορισμός βαρδιών/αναπληρώσεων","Ενημέρωση ομάδων για κανάλια επικοινωνίας","Περιοδική σύνοψη διαθέσιμου δυναμικού"]',
'["Δηλώστε διαθέσιμα άτομα, δεξιότητες και χρόνο παραμονής.","Περιμένετε ανάθεση ρόλου πριν κινηθείτε.","Ενημερώστε άμεσα για αλλαγή διαθεσιμότητας."]',
'["Ήταν καθαρή η ανάθεση ρόλων?","Πόσο γρήγορα καταγράφηκαν οι εθελοντές?","Τι χρειάζεται για καλύτερες βάρδιες?"]'),
('coast_guard', 'Έρευνα στη θάλασσα', 'Πρωτόκολλο έρευνας στη θάλασσα', 8, 1, 1,
'Οργάνωση τομέων έρευνας με βάση το τελευταίο γνωστό στίγμα, καιρό, ρεύματα και διαθέσιμα σκάφη/παρατηρητές.',
'["Σκάφος","VHF/ασύρματοι","Παρατηρητές","Κιάλια","Πρώτες βοήθειες","Ισοθερμικές κουβέρτες","Όχημα ακτής"]',
'["Συλλογή τελευταίου γνωστού στίγματος","Έλεγχος καιρού, ανέμου και ρευμάτων","Καταγραφή διαθέσιμων σκαφών/πληρωμάτων","Ορισμός τομέων έρευνας","Περιοδική αναφορά θέσης και ευρημάτων","Σημείο υποδοχής σε λιμένα/ακτή"]',
'["Αναφέρετε σκάφος, πλήρωμα, καύσιμα και ETA.","Κινηθείτε μόνο στον ανατεθειμένο τομέα.","Στείλτε άμεσα στίγμα για κάθε εύρημα."]',
'["Ήταν σωστοί οι τομείς έρευνας?","Πόσο καλά λειτούργησε η επικοινωνία VHF/κινητού?","Τι επηρέασε περισσότερο την έρευνα?"]'),
('coast_guard', 'Ναυτικό ατύχημα', 'Πρωτόκολλο ναυτικού ατυχήματος', 8, 1, 1,
'Υποστήριξη ναυτικού ατυχήματος με προτεραιότητα σε ασφάλεια επιβαινόντων, πρώτες βοήθειες, ρύπανση και ασφαλή πρόσβαση.',
'["Σκάφος","Πρώτες βοήθειες","VHF/ασύρματοι","Ισοθερμικές κουβέρτες","Αντιρρυπαντικά μέσα","Όχημα"]',
'["Επιβεβαίωση τύπου ατυχήματος και αριθμού επιβαινόντων","Ορισμός ασφαλούς σημείου προσέγγισης","Καταγραφή τραυματιών/αγνοουμένων","Έλεγχος πιθανής ρύπανσης","Προετοιμασία υποδοχής διασωθέντων","Συντονισμός με λιμενικές/υγειονομικές αρχές"]',
'["Αναφέρετε διαθέσιμο μέσο, προσωπικό και ETA.","Προτεραιότητα σε τραυματίες και υποθερμία.","Αναφέρετε άμεσα καύσιμα, ρύπανση ή αγνοούμενους."]',
'["Ήταν σαφής ο αριθμός επιβαινόντων?","Υπήρξε επαρκής υποστήριξη πρώτων βοηθειών?","Τι χρειάζεται για ταχύτερη υποδοχή στο λιμάνι?"]'),
('coast_guard', 'Απεγκλωβισμός σκάφους', 'Πρωτόκολλο απεγκλωβισμού σκάφους', 5, 1, 1,
'Συνδρομή σε σκάφος με προτεραιότητα στην ασφάλεια επιβαινόντων, την αποφυγή ρύπανσης και την ασφαλή ρυμούλκηση/απεγκλωβισμό από αρμόδιους.',
'["Σκάφος υποστήριξης","VHF/ασύρματοι","Σχοινιά/ρυμούλκηση","Πρώτες βοήθειες","Αντιρρυπαντικά μέσα","Όχημα ακτής"]',
'["Επιβεβαίωση θέσης και κατάστασης σκάφους","Έλεγχος επιβαινόντων και τραυματισμών","Έλεγχος καιρού/ρεύματος και κινδύνου ρύπανσης","Συντονισμός με κατάλληλο μέσο συνδρομής","Προετοιμασία σημείου παραλαβής αν χρειαστεί","Συνεχής ενημέρωση θέσης"]',
'["Στείλτε θέση, κατάσταση επιβαινόντων και κίνδυνο ρύπανσης.","Μην επιχειρείτε ρυμούλκηση χωρίς κατάλληλη εντολή/μέσο.","Αναφέρετε άμεσα αλλαγή καιρού ή εισροή υδάτων."]',
'["Ήταν επαρκές το διαθέσιμο μέσο συνδρομής?","Υπήρξε κίνδυνος ρύπανσης?","Τι δυσκόλεψε την προσέγγιση?"]'),
('coast_guard', 'Υποστήριξη λιμένα', 'Πρωτόκολλο υποστήριξης λιμένα', 5, 1, 0,
'Υποστήριξη λειτουργίας λιμένα με έλεγχο ροών, ενημέρωση πολιτών, σήμανση και συνδρομή σε έκτακτες ανάγκες.',
'["Όχημα","Σήμανση","Ασύρματοι","Φακοί","Πρώτες βοήθειες","Ομάδα ενημέρωσης"]',
'["Ορισμός σημείων ελέγχου/υποστήριξης","Καταγραφή ροών πολιτών και οχημάτων","Σήμανση επικίνδυνων ή κλειστών ζωνών","Προετοιμασία σημείου πρώτων βοηθειών","Ενημέρωση ομάδων για κανάλια επικοινωνίας","Περιοδική αναφορά κατάστασης λιμένα"]',
'["Αναλάβετε σημείο υποστήριξης και αναφέρετε κατάσταση.","Κρατήστε ανοιχτές κρίσιμες διελεύσεις.","Αναφέρετε άμεσα συνωστισμό, τραυματισμό ή αποκλεισμό."]',
'["Ποιο σημείο είχε τη μεγαλύτερη πίεση?","Ήταν επαρκής η σήμανση?","Τι χρειάζεται για καλύτερη ροή πολιτών/οχημάτων?"]'),
('coast_guard', 'Μεταφορά / συνδρομή', 'Πρωτόκολλο μεταφοράς και συνδρομής', 4, 1, 1,
'Οργάνωση ασφαλούς μεταφοράς ή συνδρομής με καταγραφή ατόμων, προορισμού, μέσου και κατάστασης υγείας.',
'["Όχημα","Σκάφος όπου απαιτείται","Πρώτες βοήθειες","Ισοθερμικές κουβέρτες","Ασύρματοι","Λίστα μεταφερομένων"]',
'["Επιβεβαίωση αιτήματος και αριθμού ατόμων","Καταγραφή αφετηρίας, προορισμού και μέσου","Έλεγχος ανάγκης πρώτων βοηθειών","Ανάθεση ομάδας/οχήματος/σκάφους","Επιβεβαίωση παραλαβής και άφιξης","Αναφορά τυχόν καθυστέρησης ή αλλαγής διαδρομής"]',
'["Αναφέρετε διαθέσιμο μέσο, άτομα και ETA.","Επιβεβαιώστε παραλαβή και άφιξη.","Αναφέρετε άμεσα ιατρική ανάγκη ή αλλαγή διαδρομής."]',
'["Ήταν σαφές το αίτημα συνδρομής?","Υπήρξε καθυστέρηση στη μεταφορά?","Τι χρειάζεται για ασφαλέστερη διαδικασία?"]');

INSERT INTO event_playbooks
(category_id, authority_type, title, default_people, require_vehicle, require_medical, instructions, capabilities_json, checklist_json, messages_json, debrief_questions_json)
SELECT c.id, t.authority_type, t.title, t.default_people, t.require_vehicle, t.require_medical,
       t.instructions, t.capabilities_json, t.checklist_json, t.messages_json, t.debrief_questions_json
FROM tmp_event_playbooks_complete t
JOIN event_categories c ON c.authority_type = t.authority_type AND c.name = t.category_name
ON DUPLICATE KEY UPDATE
  authority_type = VALUES(authority_type),
  title = VALUES(title),
  default_people = VALUES(default_people),
  require_vehicle = VALUES(require_vehicle),
  require_medical = VALUES(require_medical),
  instructions = VALUES(instructions),
  capabilities_json = VALUES(capabilities_json),
  checklist_json = VALUES(checklist_json),
  messages_json = VALUES(messages_json),
  debrief_questions_json = VALUES(debrief_questions_json);

DROP TEMPORARY TABLE tmp_event_playbooks_complete;
